def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        complexity_factor = 1.0
        decay_rate = 0.9
        enhancement = 1.0
        penalty = 0.0
        bonus = 0.0
        spike = 0.0
        for m in range(1, 15):
            if m % 4 == 0:
                complexity_factor *= 1.07 + 0.015 * m
            elif m % 6 == 0:
                complexity_factor *= 0.92 - 0.007 * m
            if ratio < 0.08 * m:
                score += (np.exp(-ratio * m) + m ** 1.5) * complexity_factor
            elif 0.08 * m <= ratio <= 0.7:
                score += (np.sin(ratio * m) * m ** 2 + np.log1p(m)) * complexity_factor / (m + 1)
            else:
                score += (m ** 3 / (1 + np.exp(ratio))) * complexity_factor * (0.9 + 0.1 * np.cos(m))
            if (cap + m * m * 2) % 9 == 0:
                penalty += np.tanh((cap - item) / (m + 2))
            elif (cap * m) % 11 == 0:
                penalty -= np.arctan(ratio * m)
            if m == 7:
                for n in range(1, 7):
                    diff = cap - item * n * n
                    if diff > 0:
                        if diff % (n + 3) == 1:
                            bonus += np.log1p(diff) / (n + 2)
                        else:
                            bonus -= (diff ** 0.8) / (n + 4)
                    else:
                        bonus -= (abs(diff) ** 1.7) / (n + 5)
            if ratio > 0.75 and m % 3 == 0:
                enhancement *= 1.12 + 0.025 * m
            elif ratio < 0.25 and m % 5 == 0:
                enhancement *= 0.88 - 0.012 * m
            if m % 5 == 2 and cap % (m + 2) == 0:
                spike += np.cos(m * ratio) * 0.7
            if m % 2 == 1 and cap % 3 == 0:
                decay_rate *= 0.97
            else:
                decay_rate *= 1.01
        adjusted_score = score + penalty * 0.9 + bonus + spike * 0.5
        adjusted_score *= enhancement
        if adjusted_score < 0:
            priorities[i] = -adjusted_score * (np.log1p(cap + item * 2) + np.sqrt(cap)) * decay_rate
        else:
            if cap > item * 3.5:
                priorities[i] = -adjusted_score / (np.sqrt(cap) + 2) * (1 + ratio * 1.1) * decay_rate
            else:
                exp_factor = np.exp(- (ratio - 0.5)**2)
                priorities[i] = -adjusted_score / (cap + 5) * exp_factor * decay_rate
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        if i % 2 == 0:
            priorities[i] *= 1.01
        else:
            priorities[i] *= 0.99
    return priorities
